// BAD: block.gaslimit varies by network and over time
// require(items.length < block.gaslimit / 50000, "batch too large");

// GOOD: use an explicit, governance controlled bound instead
uint256 public constant MAX_BATCH_SIZE = 100;

function processBatch(uint256[] calldata items) external {
    require(items.length <= MAX_BATCH_SIZE, "batch too large");
    for (uint256 i = 0; i < items.length; i++) {
        _process(items[i]);
    }
}

// If you need to bound work by available gas, check gasleft() for THIS call:
function drainQueue() external {
    while (queue.length > 0 && gasleft() > 60_000) {
        _process(queue[queue.length - 1]);
        queue.pop();
    }
}
